#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,K,L; scanf("%d %d %d", &N, &K, &L);
        if(N==1){
            printf("1\n");
            continue;
        }
        if(K==1 || (long long)K*L < N){
            printf("-1\n");
            continue;
        }
        for(int i=0;i<N;i++){
            int player = (i % K) + 1;
            if(i) printf(" ");
            printf("%d", player);
        }
        printf("\n");
    }
    return 0;
}

